const input = $input.item.json;
const isoWeek = $node['Preparar Contexto e Prompt'].json.isoWeek;
const dataFormatada = $node['Preparar Contexto e Prompt'].json.dataFormatada;

let conteudo_gemini = '';
try {
  const resp = input;
  if (resp.candidates && resp.candidates[0] && resp.candidates[0].content) {
    conteudo_gemini = resp.candidates[0].content.parts.map(p => p.text).join('');
  } else if (resp.error) {
    conteudo_gemini = 'ERRO API Gemini: ' + JSON.stringify(resp.error);
  } else {
    conteudo_gemini = 'RESPOSTA INESPERADA: ' + JSON.stringify(resp).slice(0,500);
  }
} catch(e) {
  conteudo_gemini = 'ERRO ao parsear resposta: ' + e.message;
}

const relatorio = `# INTELLIGENCE HUB -- TRACK TRENDS\n## Relatório Semana ${isoWeek} · Gerado automaticamente · W-9 n8n\n\n> Cadencia: semanal (segunda-feira 8h BRT)\n> Fonte: Gemini 2.0 Flash com Google Search Grounding\n> Processamento: autonomo via n8n EasyPanel\n\n---\n\n${conteudo_gemini}\n\n---\n\n## PENDENTE\nStatus: AGUARDANDO_VEREDITO\nGerado em: ${dataFormatada}\nAdicionar entrada em INTELLIGENCE_HUB/PENDING_REVIEW.md apos validar.\n\n*W-9 Auto-gerado · ${dataFormatada} · Alimentar NotebookLM: INTELLIGENCE_HUB/TRENDS/*\n`;

const relatorio_b64 = Buffer.from(relatorio, 'utf8').toString('base64');

return [{ json: {
  relatorio: relatorio,
  relatorio_b64: relatorio_b64,
  isoWeek: isoWeek,
  dataFormatada: dataFormatada,
  githubToken: $node['Preparar Contexto e Prompt'].json.githubToken,
  telegramToken: $node['Preparar Contexto e Prompt'].json.telegramToken,
  telegramChatId: $node['Preparar Contexto e Prompt'].json.telegramChatId,
  githubOwner: $node['Preparar Contexto e Prompt'].json.githubOwner,
  githubRepo: $node['Preparar Contexto e Prompt'].json.githubRepo,
  reportPath: $node['Preparar Contexto e Prompt'].json.reportPath
}}];

const rawFile = $input.item.json;
const prev = $node['Telegram -- Notificar Diretor'].json;
const isoWeek = prev.isoWeek || '';
const dataFormatada = prev.dataFormatada || new Date().toISOString().slice(0,10);
const reportPath = prev.reportPath || '';

let conteudoAtual = '';
let sha = '';
try {
  sha = rawFile.sha || '';
  conteudoAtual = Buffer.from((rawFile.content||'').replace(/\n/g,''), 'base64').toString('utf8');
} catch(e) {
  conteudoAtual = '';
}

const novaLinha = `| ${dataFormatada} | TRENDS | \`${reportPath}\` | AGUARDANDO_VEREDITO |`;
const novoConteudo = conteudoAtual.replace(
  '| *(Antigravity adiciona aqui ao concluir cada relatório)* | — | — | — |',
  novaLinha + '\n| *(Antigravity adiciona aqui ao concluir cada relatório)* | — | — | — |'
);

const novoConteudo_b64 = Buffer.from(novoConteudo, 'utf8').toString('base64');

return [{ json: {
  conteudo_b64: novoConteudo_b64,
  sha: sha,
  githubToken: $node['Preparar Contexto e Prompt'].json.githubToken,
  githubOwner: $node['Preparar Contexto e Prompt'].json.githubOwner,
  githubRepo: $node['Preparar Contexto e Prompt'].json.githubRepo
}}];
